// 1. 获取前置节点的数据，并做兼容处理
const raw = $input.item.json;
let overview = raw.courseOverview;

if (!overview && raw.text) {
  try {
    overview = JSON.parse(raw.text).courseOverview;
  } catch(e) {}
}
if (!overview) {
  overview = raw; // 兜底逻辑
}

// 2. 提取大模型生成的生图提示词
let generatedPrompt = overview.themeImagePrompt || "";
// 仅保留 cj_vector_style 维持基础画风，加入强力的无人物/文字兜底词
const imagePrompt = `cj_vector_style, ${generatedPrompt}`;

// 3. 生成随机种子，确保每次调用的画面都不一样
const seed = Math.floor(Math.random() * 1000000000000);

// 4. 构建包含 LoRA 的 ComfyUI 工作流 (匹配 aa.json，用于纯场景生成)
const workflow = {
  "1": {
    "inputs": {
      "unet_name": "z_image_turbo_bf16.safetensors",
      "weight_dtype": "default"
    },
    "class_type": "UNETLoader"
  },
  "2": {
    "inputs": {
      "vae_name": "ae.safetensors"
    },
    "class_type": "VAELoader"
  },
  "3": {
    "inputs": {
      "clip_name": "qwen_3_4b.safetensors",
      "type": "lumina2",
      "device": "default"
    },
    "class_type": "CLIPLoader"
  },
  "4": {
    "inputs": {
      "shift": 3,
      "model": [ "1", 0 ]
    },
    "class_type": "ModelSamplingAuraFlow"
  },
  "5": {
    "inputs": {
      "width": 1968,
      "height": 1152,
      "batch_size": 1
    },
    "class_type": "EmptySD3LatentImage"
  },
  "7": {
    "inputs": {
      // 在原版负面提示词基础上，加入了屏蔽人物和文字的指令
      "text": "people, humans, characters, animals, text, fonts, letters, watermark, blurry, 3d, realistic, complex textures, bad anatomy, deformed, shadows, gradients",
      "clip": [ "3", 0 ]
    },
    "class_type": "CLIPTextEncode"
  },
  "101": {
    "inputs": {
      "lora_name": "poppy.safetensors",
      "strength_model": 0.8,
      "strength_clip": 1,
      "model": [ "4", 0 ],
      "clip": [ "3", 0 ]
    },
    "class_type": "LoraLoader"
  },
  "102": {
    "inputs": {
      "text": imagePrompt, // <--- 注入处理后的纯净场景提示词
      "clip": [ "101", 1 ]
    },
    "class_type": "CLIPTextEncode"
  },
  "103": {
    "inputs": {
      "seed": seed,
      "steps": 20,
      "cfg": 1.5,
      "sampler_name": "euler",
      "scheduler": "simple",
      "denoise": 1,
      "model": [ "101", 0 ],
      "positive": [ "102", 0 ],
      "negative": [ "7", 0 ],
      "latent_image": [ "5", 0 ]
    },
    "class_type": "KSampler"
  },
  "104": {
    "inputs": {
      "samples": [ "103", 0 ],
      "vae": [ "2", 0 ]
    },
    "class_type": "VAEDecode"
  },
  "105": {
    "inputs": {
      "filename_prefix": "Universal_Scene",
      "images": [ "104", 0 ]
    },
    "class_type": "SaveImage"
  }
};

// 5. 返回组装好的对象，将大模型生成的概览数据一起透传下去
return {
  courseOverview: overview, 
  comfyuiPayload: { 
    prompt: workflow 
  }
};

const promptId = $input.item.json.prompt_id;

// 去拿"概览生成"或者"构建图片工作流"里透传下来的纯净 JSON
const cleanCourseOverview = $('构建图片工作流').first().json.courseOverview;

const comfyUrl = "https://vcbj5meqyp1y7ifw-8188.container.x-gpu.com";
const maxAttempts = 600;

for (let i = 0; i < maxAttempts; i++) {
  // 每 3 秒查一次
  await new Promise(r => setTimeout(r, 3000));

  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: `${comfyUrl}/history/${promptId}`,
      json: true
    });

    const taskData = Object.values(res)[0];

    if (taskData && taskData.outputs) {
      let images = [];
      // 动态遍历所有 output 节点，寻找里面包含 images 数组的节点（无视节点ID变动）
      for (const nodeId in taskData.outputs) {
        if (taskData.outputs[nodeId].images && taskData.outputs[nodeId].images.length > 0) {
          images = taskData.outputs[nodeId].images;
          break;
        }
      }

      if (images.length > 0) {
        const img = images[0];
        const imageUrl = `${comfyUrl}/view?filename=${img.filename}&subfolder=${img.subfolder || ''}&type=${img.type || 'output'}`;

        return {
          courseOverview: cleanCourseOverview,
          themeImageUrl: imageUrl
        };
      }
    }

    if (taskData?.status?.status_str === 'error') {
      return {
        courseOverview: cleanCourseOverview,
        themeImageUrl: null,
        error: '图片生成失败(ComfyUI内部报错)'
      };
    }
  } catch (e) {
    console.log("轮询报错，继续重试:", e.message);
  }
}

return {
  courseOverview: cleanCourseOverview,
  themeImageUrl: null,
  error: '图片生成超时'
};
